212	fn run_command(result: Result<(), Box<dyn std::error::Error>>) -> ExitCode {
213	    match result {
214	        Ok(()) => ExitCode::SUCCESS,
215	        Err(e) => {
216	            error!("{e}");
217	            ExitCode::FAILURE
218	        }
219	    }
220	}
221	
222	/// Permanent sanity check for the `main`-bookmark tracking state
223	/// in both repos of the dual-repo workspace. Prints one line on
224	/// entry and one on exit of every command. If entry and exit
225	/// differ, the executing command is the culprit; if entry differs
226	/// from the previous command's exit, something *between*
227	/// invocations broke it. Originally added in 0.37.2 as a temporary
228	/// diagnostic; promoted to permanent in 0.37.4 after the user
229	/// reported "happens more than once" — the signal is worth keeping
230	/// in place until confidence in its correctness is well-established
231	/// across varied use, at which point a "silent when clean"
232	/// refinement would remove the steady-state noise without losing
233	/// detection value (see `notes/todo.md`).
234	///
235	/// Walks up from cwd to locate the workspace root (the directory
236	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
237	/// and `<root>/.claude`. Same labeling whether the user runs from
238	/// the app root, from `.claude`, or from any subdir.
239	fn bm_track(phase: &str, command_name: &str) {
240	    let header = format!("bm-track {phase} vc-x1 {command_name}");
241	    let root = match common::find_workspace_root() {
242	        Some(r) => r,
243	        None => {
244	            log::info!("{header}: no-workspace");
245	            return;
246	        }
247	    };
248	    let repos: [(std::path::PathBuf, &str); 2] =
249	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
250	    let mut parts: Vec<String> = Vec::new();
251	    for (repo, label) in repos {
252	        if !repo.join(".jj").exists() {
253	            parts.push(format!("{label}(main)=no-jj"));
254	            continue;
255	        }
256	        match bm_track_one(&repo, "main", "origin") {
257	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
258	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
259	            Err(e) => parts.push(format!(
260	                "{label}(main)=err({})",
261	                e.lines().next().unwrap_or("")
262	            )),
263	        }
264	    }
265	    log::info!("{header}: {}", parts.join(", "));
266	}
267	
268	/// Query jj for whether `bookmark` in `repo` is tracking `remote`.
269	/// Returns `Ok(true)` if the tracked-list entry for `bookmark` shows
270	/// an `@<remote>` line (in any form — `@origin:` when synced, or
271	/// `@origin (ahead by N commits):` / similar when divergent — both
272	/// still count as tracking). `Ok(false)` when no such line exists
273	/// (bookmark isn't tracking this remote or doesn't exist). `Err` on
274	/// subprocess failure.
275	fn bm_track_one(repo: &Path, bookmark: &str, remote: &str) -> Result<bool, String> {
276	    let repo_str = repo.to_string_lossy();
277	    let output = std::process::Command::new("jj")
278	        .args(["bookmark", "list", "--tracked", bookmark, "-R", &repo_str])
279	        .output()
280	        .map_err(|e| format!("spawn: {e}"))?;
281	    if !output.status.success() {
282	        return Err(String::from_utf8_lossy(&output.stderr).trim().to_string());
283	    }
284	    let stdout = String::from_utf8_lossy(&output.stdout);
285	    // Accept both the synced form (`@origin:`) and the decorated
286	    // divergent form (`@origin (ahead by N commits):`), which still
287	    // represents a tracking relationship.
288	    let colon = format!("@{remote}:");
289	    let paren = format!("@{remote} ");
290	    Ok(stdout.lines().any(|l| {
291	        let t = l.trim_start();
292	        t.starts_with(&colon) || t.starts_with(&paren)
293	    }))
294	}
295	
296	fn main() -> ExitCode {
297	    CompleteEnv::with_factory(cli_with_banner).complete();
298	    let matches = cli_with_banner().get_matches();
299	    let cli = match Cli::from_arg_matches(&matches) {
300	        Ok(cli) => cli,
301	        Err(e) => {
302	            e.exit();
303	        }
304	    };
305	
306	    let log_path = cli.log.as_ref().map(|p| p.to_string_lossy().to_string());
307	    logging::CliLogger::init(cli.verbose, log_path.as_deref());
308	
309	    // The detached `finalize --exec` re-entry is the bot's
310	    // session-end child; it shouldn't print the banner (extra
311	    // chatter in its log) or surface user-facing failure markers
312	    // (those are meant for the user's next interactive run).
313	    let is_detached_exec = matches!(
314	        cli.command,
315	        Commands::Finalize(ref f) if f.exec
316	    );
317	
318	    // `-L` / `--no-label` on the read-only multi-repo subcommands
319	    // (chid, desc, list, show) makes their output script-parseable
320	    // — adding a leading `vc-x1 X.Y.Z` line would break that. Skip
321	    // the banner whenever the active subcommand has the flag set.
322	    let suppress_banner = match &cli.command {
323	        Commands::Chid(a) => a.common.no_label,
324	        Commands::Desc(a) => a.common.no_label,
325	        Commands::List(a) => a.common.no_label,
326	        Commands::Show(a) => a.common.no_label,
327	        _ => false,
328	    };
329	
330	    if !is_detached_exec {
331	        if !suppress_banner {
332	            // Banner on every normal run, mirroring what `--help`
333	            // shows at the top.
334	            log::info!("{BANNER}");
335	        }
336	        finalize::surface_previous_failures();
337	    }
338	
339	    // Command name for bm-track output (first positional arg after
340	    // the binary; clap has already validated it by the time we get here).
341	    let command_name = std::env::args().nth(1).unwrap_or_else(|| "?".to_string()); // OK: default when somehow invoked without a subcommand
342	
343	    if !is_detached_exec {
344	        bm_track("enter", &command_name);
345	    }
346	
347	    let exit_code = match cli.command {
348	        Commands::Chid(chid_args) => run_command(chid::chid(&chid_args)),
349	        Commands::Desc(desc_args) => run_command(desc::desc(&desc_args)),
350	        Commands::List(list_args) => run_command(list::list(&list_args)),
351	        Commands::Show(show_args) => run_command(show::show(&show_args)),
352	        Commands::ValidateDesc(validate_desc_args) => {
353	            run_command(validate_desc::validate_desc(&validate_desc_args))
354	        }
355	        Commands::FixDesc(fix_desc_args) => run_command(fix_desc::fix_desc(&fix_desc_args)),
356	        Commands::Clone(clone_args) => run_command(clone::clone_repo(&clone_args)),
357	        Commands::Init(init_args) => {
358	            let ctx = match context::Context::load() {
359	                Ok(c) => c,
360	                Err(e) => {
361	                    error!("{e}");
362	                    return ExitCode::FAILURE;
363	                }
364	            };
365	            let params = init::InitParams::from(&init_args);
366	            run_command(init::init(&ctx, &params))
367	        }
368	        Commands::Symlink(symlink_args) => run_command(symlink::symlink(&symlink_args)),
369	        Commands::Sync(sync_args) => run_command(sync::sync(&sync_args)),
370	        Commands::Finalize(finalize_args) => {
371	            let opts = match finalize_args.into_opts(cli.log) {
372	                Ok(opts) => opts,
373	                Err(e) => {
374	                    error!("{e}");
375	                    return ExitCode::FAILURE;
376	                }
377	            };
378	            run_command(finalize::finalize(&opts))
379	        }
380	        Commands::Push(push_args) => run_command(push::push(&push_args)),
381	    };
382	
383	    if !is_detached_exec {
384	        bm_track("exit ", &command_name);
385	    }
386	
387	    exit_code
388	}
